import json
import urllib.request as request
import urllib.parse as urlparse
import socket
import ipaddress

def _is_safe_url(url):
    try:
        parsed = urlparse.urlparse(url)
        if parsed.scheme not in ('http', 'https'):
            return False

        hostname = parsed.hostname
        if not hostname:
            return False

        try:
            ip = socket.gethostbyname(hostname)
        except socket.gaierror:
            return False

        try:
            ip_addr = ipaddress.ip_address(ip)
            if ip_addr.is_private or ip_addr.is_loopback or ip_addr.is_link_local or ip_addr.is_unspecified:
                return False
        except ValueError:
            return False

        # Also check the original URL for dangerous patterns (e.g., localhost, 127.0.0.1)
        if 'localhost' in hostname.lower() or hostname in ('127.0.0.1', '::1', '0.0.0.0'):
            return False

        return True
    except Exception:
        return False

def readJSON(url):
    '''
    Read a json file from a url
    and return the parsed json object
    '''
    if not _is_safe_url(url):
        raise ValueError("Invalid or unsafe URL")

    try:
        with request.urlopen(url, timeout=10) as response:
            data = response.read()
            return json.loads(data.decode('utf-8'))
    except Exception:
        raise
